#[test]
#[cfg(feature = "filters-smooth")]
fn smooth_convergence() {
    // More iterations should produce a smoother (more spherical) mesh
    let pd = test_sphere();
    let s10 = vtk_pure_rs::filters::smooth::smooth::smooth(&pd, 10, 0.5, true);
    let s100 = vtk_pure_rs::filters::smooth::smooth::smooth(&pd, 100, 0.5, true);
    // Measure "sphericity": std dev of distance from center
    fn sphericity(mesh: &PolyData) -> f64 {
        let n = mesh.points.len() as f64;
        let mut sum_r = 0.0;
        let mut sum_r2 = 0.0;
        for i in 0..mesh.points.len() {
            let p = mesh.points.get(i);
            let r = (p[0]*p[0]+p[1]*p[1]+p[2]*p[2]).sqrt();
            sum_r += r;
            sum_r2 += r * r;
        }
        let mean = sum_r / n;
        (sum_r2 / n - mean * mean).max(0.0).sqrt()
    }
    // Both smoothed versions should have reasonable sphericity (not exploded)
    assert!(sphericity(&s10) < 0.1, "s10 sphericity too high: {:.4}", sphericity(&s10));
    assert!(sphericity(&s100) < 0.1, "s100 sphericity too high: {:.4}", sphericity(&s100));
}

